'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/lib/auth-context'
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Checkbox } from "@/components/ui/checkbox"
import { useToast } from "@/components/ui/use-toast"

export default function AuthPage() {
  const router = useRouter()
  const { login } = useAuth()
  const { toast } = useToast()
  
  // State for Login
  const [loginEmail, setLoginEmail] = useState('')
  const [loginPass, setLoginPass] = useState('')
  
  // State for Register
  const [regEmail, setRegEmail] = useState('')
  const [regPass, setRegPass] = useState('')

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    // Mock login logic
    if (loginEmail && loginPass) {
       // Call login function from context
       // Assuming login is successful for demo
       toast({ title: "Login successful" })
       router.push('/account') 
    }
  }

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault()
    // Mock register logic
    toast({ title: "Registration successful", description: "Please check your email." })
  }

  return (
    <div className="min-h-screen bg-white py-16 px-4 font-sans">
      <div className="container mx-auto max-w-6xl">
        
        {/* Split Layout: 2 columns on desktop, 1 column on mobile */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 md:gap-24 relative">
          
          {/* Vertical Divider (Desktop only) */}
          <div className="hidden md:block absolute left-1/2 top-0 bottom-0 w-[1px] bg-gray-200 -translate-x-1/2"></div>

          {/* LEFT COLUMN: LOGIN */}
          <div className="space-y-6">
            <h2 className="text-2xl font-bold uppercase tracking-wide text-black">
              Login
            </h2>
            
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <Label htmlFor="login-email" className="text-base font-medium text-gray-700">
                  Username or email address <span className="text-red-500">*</span>
                </Label>
                <Input 
                  id="login-email" 
                  type="text" 
                  value={loginEmail}
                  onChange={(e) => setLoginEmail(e.target.value)}
                  className="h-12 border-gray-300 rounded-sm focus:ring-0 focus:border-black transition-colors"
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="login-pass" className="text-base font-medium text-gray-700">
                  Password <span className="text-red-500">*</span>
                </Label>
                <Input 
                  id="login-pass" 
                  type="password" 
                  value={loginPass}
                  onChange={(e) => setLoginPass(e.target.value)}
                  className="h-12 border-gray-300 rounded-sm focus:ring-0 focus:border-black transition-colors"
                  required
                />
              </div>

              <div className="flex items-center space-x-2">
                <Checkbox id="remember" className="rounded-sm border-gray-300 data-[state=checked]:bg-black data-[state=checked]:border-black" />
                <label
                  htmlFor="remember"
                  className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 text-gray-700"
                >
                  Remember me
                </label>
              </div>

              <div className="pt-2">
                <Button 
                  type="submit" 
                  className="bg-black hover:bg-gray-800 text-white font-bold uppercase py-6 px-8 rounded-sm text-sm tracking-wider"
                >
                  Log In
                </Button>
              </div>
              
              <div>
                <a href="#" className="text-sm text-blue-600 hover:underline">
                  Lost your password?
                </a>
              </div>
            </form>
          </div>

          {/* RIGHT COLUMN: REGISTER */}
          <div className="space-y-6">
            <h2 className="text-2xl font-bold uppercase tracking-wide text-black">
              Register
            </h2>

            <form onSubmit={handleRegister} className="space-y-6">
              <div className="space-y-2">
                <Label htmlFor="reg-email" className="text-base font-medium text-gray-700">
                  Email address <span className="text-red-500">*</span>
                </Label>
                <Input 
                  id="reg-email" 
                  type="email" 
                  value={regEmail}
                  onChange={(e) => setRegEmail(e.target.value)}
                  className="h-12 border-gray-300 rounded-sm focus:ring-0 focus:border-black transition-colors"
                  required
                />
              </div>

              {/* Password field included for functionality */}
              <div className="space-y-2">
                <Label htmlFor="reg-pass" className="text-base font-medium text-gray-700">
                  Password <span className="text-red-500">*</span>
                </Label>
                <Input 
                  id="reg-pass" 
                  type="password" 
                  value={regPass}
                  onChange={(e) => setRegPass(e.target.value)}
                  className="h-12 border-gray-300 rounded-sm focus:ring-0 focus:border-black transition-colors"
                  required
                />
              </div>

              <div className="text-sm text-gray-600 space-y-4 leading-relaxed">
                <p>
                  A link to set a new password will be sent to your email address.
                </p>
                <p>
                  Your personal data will be used to support your experience throughout this website, to manage access to your account, and for other purposes described in our <a href="#" className="font-bold hover:underline">privacy policy</a>.
                </p>
              </div>

              <div className="pt-2">
                <Button 
                  type="submit" 
                  className="bg-black hover:bg-gray-800 text-white font-bold uppercase py-6 px-8 rounded-sm text-sm tracking-wider"
                >
                  Register
                </Button>
              </div>
            </form>
          </div>

        </div>
      </div>
    </div>
  )
}